+    });
+
+    if (hasBun) {
+      // Check version
+      const bunVer = spawn("bun", ["--version"]);
+      let version = "";
+      bunVer.stdout.on("data", (data) => {
+        version += data.toString().trim();
+      });
+      await new Promise<void>((resolve) => bunVer.on("close", () => resolve()));
+      
+      results.push({
+        check: "Bun runtime",
+        status: "ok",
+        message: `Available (v${version})`,
+      });
